def pruebaSudoku(M):
    def encontrar_vacio(tablero):
        for i in range(9):
            for j in range(9):
                if tablero[i, j] == 0:
                    return i, j
        return None

    def es_valido(tablero, fila, col, num):
        for j in range(9):
            if tablero[fila, j] == num:
                return False
        for i in range(9):
            if tablero[i, col] == num:
                return False
        inicio_fila = (fila // 3) * 3
        inicio_col = (col // 3) * 3
        for i in range(inicio_fila, inicio_fila + 3):
            for j in range(inicio_col, inicio_col + 3):
                if tablero[i, j] == num:
                    return False
        return True

    vacio = encontrar_vacio(M)
    if vacio is None:
        return True

    fila, col = vacio
    for num in range(1, 10):
        if es_valido(M, fila, col, num):
            M[fila, col] = num
            if pruebaSudoku(M):
                return True
            M[fila, col] = 0

    return False
